function GameConfig:parseGameConfig()
    local config = FileUtil.getConfigFromYml("config")
    GameConfig.initPos = VectorUtil.newVector3(config.initPos[1].x, config.initPos[1].y, config.initPos[1].z)
    GameConfig.initPosYaw = tonumber(config.initPosYaw) or 0
    GameConfig.HangUpTime = tonumber(config.HangUpTime) or 1800
    GameConfig.defaultBoySkin = tonumber(config.defaultBoySkin) or 1001
    GameConfig.defaultGirlSkin = tonumber(config.defaultGirlSkin) or 1001
    GameConfig.ExchangeRate = tonumber(config.exchangeRate) or 1
    GameConfig.AddSpeed = tonumber(config.AddSpeed) or 1
end

function GameConfig:ChangeRecordKey(oldKey, newKey, number)
    LuaTimer:schedule(function(oldKey, newKey, number)
        MaxRecordHelper:getRecord(oldKey, 1, number, function(list)
            for _, record in pairs(list) do
                local newValue = ""
                local playerNames = StringUtil.split(record.value, "#")
                for index, nameAndId in pairs(playerNames) do
                    local values = StringUtil.split(nameAndId or "", ",")
                    newValue = newValue .. values[2]
                    if index < #playerNames then
                        newValue = newValue .. "#"
                    end
                end
                MaxRecordHelper:reportOneRecord(newKey, newValue, record.score)
            end
        end)
    end, 10000, nil, oldKey, newKey, number)
end